<#
.SYNOPSIS
Example PowerShell form for the embedded launch.

.DESCRIPTION
This script creates an example form for the embedded launch.

.EXAMPLE
embeddedScript.ps1
Runs the script.

.NOTES
NAME: embeddedScript.ps1
AUTHOR: Josh Van Buren
LASTEDIT: 4/20/2026
VERSION: 1.0

#Reqires -Version 2.0
#>

#Add the types
Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing 

#Enable Windows styles for the form 
[System.Windows.Forms.Application]::EnableVisualStyles()

#Icon as a base 64 string
$iconBase64 = ""

#Scale factor for the controls 
$scaleFactor = 1

#Get the current DPI 
$currentDPI = (Get-ItemProperty -Path "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\FontDPI\" -Name "LogPixels").LogPixels

#Default DPI 96
$defaultDPI = 96

#Caleslate the scale factor
if(($currentDPI / $defaultDPI) -gt 1) { $scaleFactor = $currentDPI / $defaultDPI }
else { $scalefactor = 1 }

#Set the control sizes 
$formWidth = 300 * $scaleFactor
$formHeight = 150 * $scaleFactor
$buttonWidth = 100 * $scaleFactor
$buttonHeight = 30 * $scaleFactor

#Create the form
$testForm = New-Object System.Windows.Forms.Form

#Enable DPI for the form 
$testForm.AutoScaleMode = [System.Windows.Forms.AutoScaleMode]::Dpi

#Create the graphics for the forn
$formGraphics = $testForm.createGraphics()

#Set the form properties
$testForm.Text = "PowerShell GUI Launched Via Embedded Script"
$testForm.Size = New-Object System.Drawing.Size($formWidth, $formHeight)
$testForm.StartPosition = "CenterScreen"
$testForm.FormBorderStyle = "FixedDialog"
$testForm.MaximizeBox = $false

#Create a simple label
$formLabel = New-Object System.Windows.Forms.Label
$formLabel.Text = "PowerShell GUI Launched Via Embedded Script"
$formLabel.AutoSize = $true
$formLabel.Location = New-Object System.Drawing.Point([Math]::Ceiling(($testForm.Width - $formLabel.PreferredWidth) / 2), 20)

#Create the OK Button
$okButton = New-Object System.Windows.Forms.Button
$okButton.Text = "&OK"
$okButton.Size = New-Object System.Drawing.Size($buttonWidth, $buttonHeight)
$okButton.Location = New-Object System.Drawing.Point([Math]::Ceiling(($testForm.Width - $okButton.Width) / 2), 60)
$okButton.Add_Click({$testForm.Close()})
$okButton.TabIndex = 0
$testForm.AcceptButton = $okButton 

#Add the controls to the form 
$testForm.Controls.Add($formLabel)
$testForm.Controls.Add($okButton)

#Convert the base64 string back to bytes 
$iconAsByte = [Convert]::FromBase64String($iconBase64)

#Create a memory stream and write the icon data to it 
$iconMemoryStream = New-Object IO.MemoryStream($iconAsByte, 0, $iconAsByte.Length)
$iconMemoryStream.Write($iconAsByte, 0, $iconAsByte.Length)

#Create the icon 
$iconBitmap = New-Object System.Drawing.Bitmap($iconMemoryStream)

#Set the form icon 
$testForm.Icon = [System.Drawing.Icon]::FromHandle($iconBitmap.GetHicon())

# Show the form
$testForm.ShowDialog() | Out-Null